    /// <summary>
    /// Wire-nav step of the two-pass populate pattern. Invoked exactly
    /// once by <c>GeoDataInitializer</c> after every catalog's first-pass
    /// static ctor has run. Resolves each entity's
    /// <c>MemberCountryIso31661Alpha2Codes</c> via <c>CountryLookup</c>
    /// and populates <c>MemberCountries</c> via the friend-assembly
    /// <c>internal set</c> accessor.
    /// </summary>
    internal static void WireNav()
    {
        foreach (var entity in All)
        {
            var resolved = new List<Country>(entity.MemberCountryIso31661Alpha2Codes.Count);
            foreach (var cc in entity.MemberCountryIso31661Alpha2Codes)
            {
                if (CountryLookup.ByCode.TryGetValue(cc, out var country))
                    resolved.Add(country);
            }

            entity.MemberCountries = resolved.ToArray();
        }
    }
}
